"use client";

import React, { Component, ReactNode } from 'react';
import { WifiOff, RefreshCw, Home, AlertTriangle, Wifi } from 'lucide-react';

interface Props {
    children: ReactNode;
    fallback?: ReactNode;
}

interface State {
    hasError: boolean;
    error: Error | null;
    errorInfo: React.ErrorInfo | null;
    isOffline: boolean;
    isRetrying: boolean;
    retryCount: number;
    serviceWorkerStatus: 'supported' | 'not-supported' | 'active' | 'inactive' | 'error';
    environment: {
        isLocalhost: boolean;
        isNetworkIP: boolean;
        isProduction: boolean;
        isHTTPS: boolean;
    };
}

export class OfflineErrorBoundary extends Component<Props, State> {
    private maxRetries = 3;
    private retryTimeouts: NodeJS.Timeout[] = [];

    constructor(props: Props) {
        super(props);
        this.state = {
            hasError: false,
            error: null,
            errorInfo: null,
            isOffline: !navigator.onLine,
            isRetrying: false,
            retryCount: 0,
            serviceWorkerStatus: 'supported',
            environment: this.getEnvironmentInfo()
        };
    }

    componentDidMount() {
        // Listen for online/offline events
        window.addEventListener('online', this.handleConnectionChange);
        window.addEventListener('offline', this.handleConnectionChange);
        
        // Listen for custom network events
        window.addEventListener('network-status-change', this.handleCustomNetworkChange as EventListener);
        window.addEventListener('connection-status-check', this.handleConnectionCheck as EventListener);
        
        // Check service worker availability
        this.checkServiceWorkerAvailability();
    }

    static getDerivedStateFromError(error: Error): Partial<State> {
        return {
            hasError: true,
            error,
            isOffline: !navigator.onLine
        };
    }

    componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
        console.error('🚨 OfflineErrorBoundary caught an error:', error);
        console.error('Error Info:', errorInfo);
        
        // Check if error is network-related
        const isNetworkError = this.isNetworkError(error);
        
        this.setState({
            error,
            errorInfo,
            isOffline: isNetworkError || !navigator.onLine
        });
    }

    componentWillUnmount() {
        window.removeEventListener('online', this.handleConnectionChange);
        window.removeEventListener('offline', this.handleConnectionChange);
        window.removeEventListener('network-status-change', this.handleCustomNetworkChange as EventListener);
        window.removeEventListener('connection-status-check', this.handleConnectionCheck as EventListener);
        
        // Clear any pending timeouts
        this.retryTimeouts.forEach(timeout => clearTimeout(timeout));
    }

    // Get environment information
    private getEnvironmentInfo = () => {
        if (typeof window === 'undefined') {
            return { isLocalhost: false, isNetworkIP: false, isProduction: false, isHTTPS: false };
        }
        
        const hostname = window.location.hostname;
        const isLocalhost = hostname === 'localhost' || hostname === '127.0.0.1';
        const isNetworkIP = /^192\.168\./.test(hostname) || /^10\./.test(hostname);
        const isProduction = !isLocalhost && !isNetworkIP;
        const isHTTPS = window.location.protocol === 'https:';
        
        return { isLocalhost, isNetworkIP, isProduction, isHTTPS };
    };

    // Check service worker availability and status
    private checkServiceWorkerAvailability = async () => {
        if (!('serviceWorker' in navigator)) {
            this.setState({ serviceWorkerStatus: 'not-supported' });
            return;
        }

        try {
            const registration = await navigator.serviceWorker.getRegistration();
            if (registration && registration.active) {
                this.setState({ serviceWorkerStatus: 'active' });
            } else {
                this.setState({ serviceWorkerStatus: 'inactive' });
            }
        } catch (error) {
            console.warn('Service worker check failed:', error);
            this.setState({ serviceWorkerStatus: 'error' });
        }
    };

    // Enhanced network error detection
    private isNetworkError = (error: Error): boolean => {
        const networkErrorMessages = [
            'Failed to fetch',
            'NetworkError',
            'network error',
            'fetch failed',
            'connection',
            'offline',
            'timeout',
            'ECONNREFUSED',
            'ENOTFOUND',
            'ERR_INTERNET_DISCONNECTED',
            'ERR_NAME_NOT_RESOLVED',
            'ERR_CONNECTION_REFUSED',
            'ERR_NETWORK_CHANGED',
            'ERR_SOCKET_TIMEOUT'
        ];
        
        return networkErrorMessages.some(msg => 
            error.message.toLowerCase().includes(msg.toLowerCase())
        );
    };

    private handleConnectionChange = () => {
        const isOffline = !navigator.onLine;
        this.setState({ isOffline });
        
        // If we come back online and had an error, try to recover
        if (!isOffline && this.state.hasError) {
            console.log('🌐 Connection restored, attempting recovery...');
            this.handleRetry();
        }
        
        // Re-check service worker when connection changes
        this.checkServiceWorkerAvailability();
    };

    private handleCustomNetworkChange = (event: Event) => {
        const customEvent = event as CustomEvent;
        const isOffline = !customEvent.detail.isOnline;
        this.setState({ isOffline });
        
        if (!isOffline && this.state.hasError) {
            console.log('🌐 Custom network event: connection restored');
            this.handleRetry();
        }
    };

    private handleConnectionCheck = (event: Event) => {
        const customEvent = event as CustomEvent;
        const isOffline = !customEvent.detail.isOnline;
        this.setState({ isOffline });
    };

    private handleRetry = () => {
        console.log('🔄 Retrying after error...');
        
        this.setState(prevState => {
            const newRetryCount = prevState.retryCount + 1;
            
            if (newRetryCount <= this.maxRetries) {
                return {
                    hasError: false,
                    error: null,
                    errorInfo: null,
                    isOffline: prevState.isOffline,
                    isRetrying: false,
                    retryCount: newRetryCount,
                    serviceWorkerStatus: prevState.serviceWorkerStatus,
                    environment: prevState.environment
                };
            } else {
                console.log('❌ Max retries reached, showing offline screen');
                return {
                    ...prevState,
                    retryCount: 0
                };
            }
        });
    };

    private handleGoHome = () => {
        // Navigate to home page without full page reload
        if (typeof window !== 'undefined') {
            window.location.hash = '#/';
            this.handleRetry();
        }
    };

    private renderOfflineScreen = () => {
        if (this.props.fallback) {
            return this.props.fallback;
        }

        const { environment, serviceWorkerStatus } = this.state;

        return (
            <div className="min-h-screen bg-gray-50 flex items-center justify-center p-6">
                <div className="max-w-md w-full">
                    <div className="bg-white rounded-3xl border border-gray-200 shadow-lg p-8 text-center">
                        {/* Offline Icon */}
                        <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-6">
                            <WifiOff className="w-10 h-10 text-gray-600" />
                        </div>

                        {/* Title */}
                        <h1 className="text-2xl font-bold text-gray-900 mb-3">
                            You're Offline
                        </h1>
                        
                        {/* Description */}
                        <p className="text-gray-600 mb-6">
                            It looks like you've lost your internet connection. Some features may not work properly until you're back online.
                        </p>

                        {/* Environment Info */}
                        {(environment.isNetworkIP || environment.isProduction) && (
                            <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 mb-6">
                                <div className="flex items-center gap-2 mb-2">
                                    <Wifi className="w-4 h-4 text-blue-600" />
                                    <span className="text-sm font-medium text-blue-800">Network Access</span>
                                </div>
                                <p className="text-xs text-blue-700">
                                    {environment.isNetworkIP 
                                        ? "Local network access detected. Service worker functionality may be limited."
                                        : environment.isProduction && !environment.isHTTPS
                                        ? "Production requires HTTPS for full offline functionality."
                                        : "Production environment with HTTPS enabled."
                                    }
                                </p>
                            </div>
                        )}

                        {/* Service Worker Status */}
                        <div className="bg-gray-50 rounded-xl p-4 mb-6">
                            <div className="flex items-center justify-center gap-2 mb-2">
                                <div className={`w-2 h-2 rounded-full ${
                                    serviceWorkerStatus === 'active' ? 'bg-green-500' :
                                    serviceWorkerStatus === 'inactive' ? 'bg-yellow-500' :
                                    serviceWorkerStatus === 'error' ? 'bg-red-500' :
                                    serviceWorkerStatus === 'not-supported' ? 'bg-gray-500' :
                                    'bg-blue-500'
                                }`}></div>
                                <span className="text-sm text-gray-600">
                                    Service Worker: {serviceWorkerStatus}
                                </span>
                            </div>
                        </div>

                        {/* Connection Status */}
                        <div className="bg-gray-50 rounded-xl p-4 mb-6">
                            <div className="flex items-center justify-center gap-2">
                                <div className={`w-2 h-2 rounded-full ${this.state.isOffline ? 'bg-red-500' : 'bg-green-500'}`}></div>
                                <span className="text-sm text-gray-600">
                                    {this.state.isOffline ? 'Disconnected' : 'Connected'}
                                </span>
                            </div>
                        </div>

                        {/* Error Details (if available) */}
                        {this.state.error && (
                            <div className="bg-red-50 border border-red-200 rounded-xl p-4 mb-6">
                                <div className="flex items-center gap-2 mb-2">
                                    <AlertTriangle className="w-4 h-4 text-red-600" />
                                    <span className="text-sm font-medium text-red-800">Error Details</span>
                                </div>
                                <p className="text-xs text-red-700 break-all">
                                    {this.state.error.message}
                                </p>
                            </div>
                        )}

                        {/* Action Buttons */}
                        <div className="space-y-3">
                            <button
                                onClick={this.handleRetry}
                                disabled={this.state.retryCount >= this.maxRetries}
                                className="w-full py-3 px-4 bg-blue-600 hover:bg-blue-700 disabled:bg-gray-300 text-white font-semibold rounded-xl transition-colors flex items-center justify-center gap-2"
                            >
                                <RefreshCw className="w-5 h-5" />
                                {this.state.retryCount >= this.maxRetries ? 'Max Retries Reached' : 'Try Again'}
                            </button>

                            <button
                                onClick={this.handleGoHome}
                                className="w-full py-3 px-4 bg-gray-100 hover:bg-gray-200 text-gray-700 font-semibold rounded-xl transition-colors flex items-center justify-center gap-2"
                            >
                                <Home className="w-5 h-5" />
                                Go to Home
                            </button>
                        </div>

                        {/* Help Text */}
                        <p className="text-xs text-gray-500 text-center mt-6">
                            Try checking your internet connection or refresh the page when you're back online.
                        </p>
                    </div>
                </div>
            </div>
        );
    };

    render() {
        if (this.state.hasError || this.state.isOffline) {
            return this.renderOfflineScreen();
        }

        return this.props.children;
    }
}
